{"code": "import json, re

# Get the result from the query
result_key = 'var_functions.query_db:8'
result_value = locals()[result_key]

# Load JSON if it's a file path
if isinstance(result_value, str) and result_value.endswith('.json'):
    with open(result_value, 'r') as f:
        businesses = json.load(f)
else:
    businesses = result_value

# Extract state and review count
state_reviews = {}
for business in businesses:
    desc = business.get('description', '')
    try:
        review_count = int(business.get('review_count', 0))
    except:
        review_count = 0

    # Match state patterns like "city, ST"
    match = re.search(r'[A-Za-z ]+, ([A-Z]{2})[,\. ]', desc)
    if match:
        state = match.group(1)
        state_reviews[state] = state_reviews.get(state, 0) + review_count

# Find top state
top_state = max(state_reviews, key=state_reviews.get)
print('__RESULT__:')
print(json.dumps({
    'top_state': top_state,
    'total_reviews': state_reviews[top_state],
    'states_found': len(state_reviews)
}))"}
